
CREATE TABLE IF NOT EXISTS users (id INT AUTO_INCREMENT PRIMARY KEY,email VARCHAR(190) UNIQUE NOT NULL,password_hash VARCHAR(255) NOT NULL,role ENUM('admin','scorer') NOT NULL DEFAULT 'admin',created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS teams (id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(120) NOT NULL,city VARCHAR(120),logo_url VARCHAR(255),created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS players (id INT AUTO_INCREMENT PRIMARY KEY,team_id INT NULL,first_name VARCHAR(120) NOT NULL,last_name VARCHAR(120) NOT NULL,number VARCHAR(10),position VARCHAR(20),photo_url VARCHAR(255),created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,INDEX(team_id),FOREIGN KEY (team_id) REFERENCES teams(id) ON DELETE SET NULL);
CREATE TABLE IF NOT EXISTS games (id INT AUTO_INCREMENT PRIMARY KEY,home_team_id INT NOT NULL,away_team_id INT NOT NULL,game_date DATE NOT NULL,location VARCHAR(190),final_home INT DEFAULT 0,final_away INT DEFAULT 0,notes TEXT,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY (home_team_id) REFERENCES teams(id) ON DELETE CASCADE,FOREIGN KEY (away_team_id) REFERENCES teams(id) ON DELETE CASCADE);
CREATE TABLE IF NOT EXISTS game_player_stats (id INT AUTO_INCREMENT PRIMARY KEY,game_id INT NOT NULL,team_id INT NOT NULL,player_id INT NOT NULL,AB INT DEFAULT 0,H INT DEFAULT 0,dbl INT DEFAULT 0,tpl INT DEFAULT 0,R INT DEFAULT 0,RBI INT DEFAULT 0,HR INT DEFAULT 0,BB INT DEFAULT 0,SO INT DEFAULT 0,SB INT DEFAULT 0,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,UNIQUE KEY uniq_gps (game_id, player_id),FOREIGN KEY (game_id) REFERENCES games(id) ON DELETE CASCADE,FOREIGN KEY (team_id) REFERENCES teams(id) ON DELETE CASCADE,FOREIGN KEY (player_id) REFERENCES players(id) ON DELETE CASCADE);
CREATE TABLE IF NOT EXISTS player_stats (id INT AUTO_INCREMENT PRIMARY KEY,player_id INT UNIQUE NOT NULL,games_played INT DEFAULT 0,AB INT DEFAULT 0,H INT DEFAULT 0,dbl INT DEFAULT 0,tpl INT DEFAULT 0,TB INT DEFAULT 0,R INT DEFAULT 0,RBI INT DEFAULT 0,HR INT DEFAULT 0,BB INT DEFAULT 0,SO INT DEFAULT 0,SB INT DEFAULT 0,AVG DECIMAL(5,3) DEFAULT 0.000,OBP DECIMAL(5,3) DEFAULT 0.000,SLG DECIMAL(5,3) DEFAULT 0.000,updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,FOREIGN KEY (player_id) REFERENCES players(id) ON DELETE CASCADE);
CREATE TABLE IF NOT EXISTS team_stats (team_id INT PRIMARY KEY,wins INT DEFAULT 0,losses INT DEFAULT 0,ties INT DEFAULT 0,runs_for INT DEFAULT 0,runs_against INT DEFAULT 0,updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,FOREIGN KEY (team_id) REFERENCES teams(id) ON DELETE CASCADE);
CREATE TABLE IF NOT EXISTS media (id INT AUTO_INCREMENT PRIMARY KEY,type ENUM('video','image') NOT NULL,title VARCHAR(190) NOT NULL,url VARCHAR(255) NOT NULL,thumbnail_url VARCHAR(255),featured TINYINT(1) DEFAULT 0,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS weekly_awards (id INT AUTO_INCREMENT PRIMARY KEY,week_start DATE NOT NULL,week_end DATE NOT NULL,player_id INT NULL,team_id INT NULL,award_type VARCHAR(120) NOT NULL,description TEXT,media_url VARCHAR(255),created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY (player_id) REFERENCES players(id) ON DELETE SET NULL,FOREIGN KEY (team_id) REFERENCES teams(id) ON DELETE SET NULL);
